const script = $json.choices?.[0]?.message?.content || "";

return {
  topic: $('rename_hook').item.json.topic,
  hook: $('rename_hook').item.json.hook,
  script: script.trim()
};

function slugify(text) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 60);
}

const today = new Date().toISOString().slice(0, 10);

return {
  date: today,
  topic: $json.topic,
  hook: $json.hook,
  script: $json.script,
  slug: slugify($json.topic),
  hook_slug: slugify($json.hook)
};

const filename = `${$json.date}_${$json.slug}_${$json.hook_slug}.json`;

const content = JSON.stringify({
  date: $json.date,
  topic: $json.topic,
  hook: $json.hook,
  script: $json.script,
  slug: $json.slug,
  hook_slug: $json.hook_slug
}, null, 2);

return {
  json: {
    filepath: `/workspace/content_factory/scripts/${filename}`,
    filename
  },
  binary: {
    data: {
      data: Buffer.from(content).toString('base64'),
      mimeType: 'application/json',
      fileName: filename
    }
  }
};
